INSERT INTO customers (id, application_date, name, email, phone, utm_source, utm_medium, utm_id, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, initial_level, program_interest, sns_accounts, reference_media, behavioral_traits, university) VALUES (E'834f09e4-3cfd-4618-8a1a-66067132c21a', E'2025-06-28', E'横谷悠', E'yokotaniyu.career@gmail.com', E'8037623225', E'fbad', E'creative2', E'120227122159740455', E'既卒', E'青山学院大学 総合文化政策学部 \n新卒でベンチャーコンサルティングファームに入社後、以下の領域でコンサルティングに従\n\n        •        官公庁（国土交通省）\n　住宅局におけるDX構想策定支援。全国展開する基幹業務システムの構想立案〜開発マネジメント（数億円規模）を担当し、導入・普及フェーズにおける施策立案やUATもリード。政策提言〜現場実装を一貫して推進。\n        •        大手損害保険会社\n　人事制度改革支援として、現場ヒアリング・人事データ分析に基づく課題整理、ToBe像策定、改革ロードマップと施策の具体化までを実行。定量・定性の両面から構造的に改革を支援。\n        •        大手食品メーカー\n　中期経営計画策定支援として、経営企画部向けの勉強会設計、業界動向・市場環境分析を通じた経営方針立案を支援。\n        •        不動産・住宅販売会社\n　Webマーケティングと営業プロセス改革を統合的に支援。広告代理店マネジメント、CRM導入、営業フロー再設計を実施。従来の飛び込み営業からWeb集客へと構造転換を図り、半年でWeb経由売上を過半にまで拡大。', E'FB広告', E'yokotaniyu.career@gmail.com', E'1998-04-17', E'ヨコタニ ユウ', E'カーニー, S&, ADL, ローランドベルガー, その他戦略コンサル, 総合コンサル（Big4、アクセンチュアなど）', E'中級：基礎的なインプットが完了し、友人や内定者と面接形式での演習等も開始している', E'関心が高い(他サービスと比較中)', E'https://x.com/', E'とくになし', E'人とは異なる視点や独創的なアイデアを出す力がある, 起業したり・自分で事業をやった経験がある（小規模でもok）, いわゆるコミュ力が高く、先輩や上司に気に入られるのが得意', E'青山学院大学');
INSERT INTO customers (id, application_date, name, email, phone, utm_source, utm_medium, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, initial_level, program_interest, sns_accounts, reference_media, hobbies, behavioral_traits, university) VALUES (E'9d7b02c3-867f-436b-8a35-aac2cbfb5f27', E'2025-06-28', E'園田里穂', E'r.sonoda1107@gmail.com', E'7090296721', E'googleads', E'303', E'既卒・中途(3年目以上7年目未満)', E'上智大学経済学部経営学科卒業後、楽天グループに入社し、現在4年目。一貫して楽天モバイル事業に携わり、初期配属基地局設置統括本部からモバイル法人事業の立ち上げに参画。事業戦略部にて主に基幹システムの開発及び大型受注時のイレギュラー対応を担当。MNPなど基幹システムの構築からオペレーションフローまで策定。フロー改善とシステム要件定義により年間250万のコストカットを実現。今年2025年8月よりSingapore Management UniversityのMBAへ進学予定。', E'Google検索', E'r.sonoda1107@gmail.com', E'1999-11-07', E'ソノダ　リホ', E'マッキンゼー, BCG', E'初心者：対策を始めたばかりでほぼ初心者', E'関心が高い', E'https://x.com/', E'特にないです。本は、現職で自分の言語力を向上させたいと考え、「考える技術・書く技術」を何度か読んで使用していました。', E'テニス、長距離走、ピラティス、バレー、など体を動かすことが好きです。余談ですが、地元福岡が大好きで、培った力を最後は全て福岡に注ぎたいと思っています。志望企業にBDGを入れているのは、戦コンで唯一福岡にオフィスがある企業で、グローバルな視点や専門性を持つ福岡が大好きな社員の方が福岡の方々をサポートしているオフィスに自身も入りたいと考えているからです。', E'人とは異なる視点や独創的なアイデアを出す力がある', E'上智大学');
