INSERT INTO customers (id, application_date, name, email, attribute, career_history, initial_channel, karte_email, birth_date, name_kana, target_companies, initial_level, program_interest, purchased_content, sns_accounts, reference_media, hobbies, behavioral_traits, university) VALUES (E'77b1dda4-453a-458e-9f6e-cc77b37af50b', E'2025-04-18', E'Ami Nakatomi', E'aminakatomicu24@gmail.com', E'既卒・中途(3年目未満)', E'2024年3月　国際基督教大学卒業\n2024年4月〜現在　ロッテベンチャーズ・ジャパン', E'note', E'aminakatomicu24@gmail.com', E'2001-01-28', E'ナカトミ　アミ', E'BCG, カーニー', E'中級：基礎的なインプットが完了し、友人や内定者と面接形式での演習等も開始している', E'関心が高い(他サービスと比較中)', E'ケース面接の教科書(note), フェルミ推定の教科書(note), フェルミ動画講座', E'https://x.com/', E'note、ブログ、YouTube', E'1. 趣味\n・旅行：海外の現地の食文化を探求するのが好き。これまでアメリカ、日本、デンマーク、ベトナムに居住経験あり。家庭でベトナム料理を食べてきた影響で、ベトナム料理が一番好き。\n・自炊：最近作った「アスパラとホタルイカのパスタ」が美味しくできた。\n・読書：小説をよく読み、特に村田沙耶香さんの作品が好き。\n・エンタメ：洋画、YouTube、ポッドキャストやスタンドアップコメディを通じて、言語感覚や多様な視点に触れるのが習慣。\n\n2. 言語・文化的バックグラウンド\n・ルーツ：母がベトナム人、父が日本人。小中高の半分を英語環境で過ごし、多文化環境に適応してきた。\n・言語：日本語・英語のバイリンガル。ベトナム語は日常会話レベルで使用可能。\n\n3. 性格・対人関係\n対人スキル：VC勤務時にはスタートアップやビジネス知識に課題を感じつつも、多様な人と積極的に関わり、相手のパッションに触れることにやりがいを感じていた。共感力と好奇心が強み。', E'人とは異なる視点や独創的なアイデアを出す力がある, 長期インターンの経験がある（新卒の方向け）, いわゆるコミュ力が高く、先輩や上司に気に入られるのが得意', E'国際基督教大学');
