INSERT INTO customers (id, application_date, name, email, utm_source, attribute, career_history, initial_channel, target_firm_type, initial_level, application_reason_karte, other_background, university) VALUES (E'5867bddc-ecee-4070-a6b3-06db9aabfcde', E'2024-10-11', E'飯星　竜馬', E'iphosi@gmail.com', E'notelp', E'既卒・中途(7年目以上)', E'中途：33歳、現在MBA留学中、昨年までIT通信系企業で新卒から7年弱勤務（営業・企画・新規事業・海外戦略）\nカリフォルニア大学ロサンゼルス校を卒業後、イノベーションとグローバルビジネスを通じて\n日本の国際競争力の向上に貢献したいという思いから、2016 年にソフトバンク(株)に新卒入社。グ\nローバル JV 立ち上げ時の多国籍チームとの橋渡し役や、社内起業制度においてゼロからのデジタ\nルプラットフォームビジネスの立ち上げ・商用化、CEO 直轄組織における海外事業の中長期戦略の\n策定等に従事し、会社のイノベーションとグローバル化を推進。現在は、グローバルな経営を学\nび、多様な環境でリーダーシップを磨くべく、シンガポール国立大学にて MBA を取得中。2025 年\n6 月に卒業予定(履修完了は 2025 年 3 月のため、4 月より勤務可能。)', E'X', E'戦略ファーム全般(マッキンゼー含む)', E'中級：基礎的なインプットが完了し、友人や内定者と面接形式での演習等も開始している', E'配布特典', E'シンガポール在住。選考序盤で11月中旬～末頃に最終面接を想定', E'その他');
